defmodule AdminDashboardWeb.UserController do
  use Phoenix.Controller
  alias AdminDashboard.UserQueries

  def index(conn, params) do
    users = case params do
      %{"role" => role} -> UserQueries.get_users_by_role(role)
      %{"status" => status} -> UserQueries.get_users_by_status(status)
      %{"search" => search} -> UserQueries.search_users(search)
      %{"id" => id} -> [UserQueries.get_user_by_id(id)]
      _ -> UserQueries.filter_users(params)
    end

    json(conn, %{users: users})
  end

  def search(conn, %{"q" => query}) do
    users = UserQueries.search_users(query)
    json(conn, %{users: users})
  end

  def by_role(conn, %{"role" => role}) do
    users = UserQueries.get_users_by_role(role)
    json(conn, %{users: users})
  end

  def by_date_range(conn, %{"start_date" => start_date, "end_date" => end_date}) do
    users = UserQueries.get_users_by_date_range(start_date, end_date)
    json(conn, %{users: users})
  end

  def sorted(conn, %{"order_by" => order_by, "direction" => direction}) do
    users = UserQueries.get_users_with_order(order_by, direction)
    json(conn, %{users: users})
  end

  def delete(conn, %{"email" => email}) do
    UserQueries.delete_user_by_email(email)
    json(conn, %{status: "deleted"})
  end

  def update_role(conn, %{"email" => email, "role" => role}) do
    UserQueries.update_user_role(email, role)
    json(conn, %{status: "updated"})
  end
